def AND_gate(a, b):
    '''AND gate: output is 1 only if both inputs are 1'''
    return a and b

def OR_gate(a, b):
    '''OR gate: output is 1 if at least one input is 1'''
    return a or b

def NOT_gate(a):
    '''NOT gate (inverter): output is complement of input'''
    return not a

# Test with truth table values
print("AND Gate:")
for a in [0, 1]:
    for b in [0, 1]:
        print(f"{a} AND {b} = {AND_gate(a, b)}")

print("\nOR Gate:")
for a in [0, 1]:
    for b in [0, 1]:
        print(f"{a} OR {b} = {OR_gate(a, b)}")

print("\nNOT Gate:")
for a in [0, 1]:
    print(f"NOT {a} = {NOT_gate(a)}")

#include <stdio.h>

// Basic logic gate functions
int AND_gate(int a, int b) {
    return a & b;  // Bitwise AND
}

int OR_gate(int a, int b) {
    return a | b;  // Bitwise OR
}

int NOT_gate(int a) {
    return !a;     // Logical NOT
}

int main() {
    printf("AND Gate Truth Table:\n");
    for (int a = 0; a <= 1; a++) {
        for (int b = 0; b <= 1; b++) {
            printf("%d AND %d = %d\n", a, b, AND_gate(a, b));
        }
    }

    printf("\nOR Gate Truth Table:\n");
    for (int a = 0; a <= 1; a++) {
        for (int b = 0; b <= 1; b++) {
            printf("%d OR %d = %d\n", a, b, OR_gate(a, b));
        }
    }

    printf("\nNOT Gate:\n");
    for (int a = 0; a <= 1; a++) {
        printf("NOT %d = %d\n", a, NOT_gate(a));
    }

    return 0;
}

public class LogicGates {

    // AND gate: returns true only if both inputs are true
    public static boolean AND(boolean a, boolean b) {
        return a && b;
    }

    // OR gate: returns true if at least one input is true
    public static boolean OR(boolean a, boolean b) {
        return a || b;
    }

    // NOT gate: inverts the input
    public static boolean NOT(boolean a) {
        return !a;
    }

    public static void main(String[] args) {
        // Testing AND gate
        System.out.println("AND Gate:");
        boolean[][] inputs = {{false, false}, {false, true}, 
                              {true, false}, {true, true}};
        for (boolean[] pair : inputs) {
            System.out.println(pair[0] + " AND " + pair[1] + 
                             " = " + AND(pair[0], pair[1]));
        }

        // Testing OR gate
        System.out.println("\nOR Gate:");
        for (boolean[] pair : inputs) {
            System.out.println(pair[0] + " OR " + pair[1] + 
                             " = " + OR(pair[0], pair[1]));
        }

        // Testing NOT gate
        System.out.println("\nNOT Gate:");
        System.out.println("NOT false = " + NOT(false));
        System.out.println("NOT true = " + NOT(true));
    }
}
